import cadquery as cq
import math

# Parametric dimensions
outer_w = 185.0
outer_h = 95.0
frame_thickness = 5.0
plate_thickness = 3.0
corner_radius = 6.0

tab_radius = 5.0
hole_diameter = 2.6

# Tab definitions: (edge, position_along_edge, outward_offset)
# edge: "top", "bottom", "left", "right"
tabs = [
    ("top", 0.23, 4.5),
    ("top", 0.52, 4.0),
    ("left", 0.18, 3.5),
    ("left", 0.72, 3.5),
    ("right", 0.36, 5.0),
    ("right", 0.92, 4.0),
    ("bottom", 0.22, 3.5),
    ("bottom", 0.58, 3.5),
    ("bottom", 0.86, 3.5),
]

def edge_point(edge, t, w, h):
    if edge == "top":
        return (-w / 2 + t * w, h / 2)
    elif edge == "bottom":
        return (-w / 2 + t * w, -h / 2)
    elif edge == "left":
        return (-w / 2, h / 2 - t * h)
    elif edge == "right":
        return (w / 2, h / 2 - t * h)
    else:
        raise ValueError("Invalid edge")

def outward_normal(edge):
    if edge == "top":
        return (0.0, 1.0)
    elif edge == "bottom":
        return (0.0, -1.0)
    elif edge == "left":
        return (-1.0, 0.0)
    elif edge == "right":
        return (1.0, 0.0)
    else:
        raise ValueError("Invalid edge")

# Main rectangular ring
outer = (
    cq.Workplane("XY")
    .rect(outer_w, outer_h)
    .extrude(plate_thickness)
    .edges("|Z")
    .fillet(corner_radius)
)

inner = (
    cq.Workplane("XY")
    .rect(outer_w - 2 * frame_thickness, outer_h - 2 * frame_thickness)
    .extrude(plate_thickness)
    .edges("|Z")
    .fillet(max(corner_radius - frame_thickness * 0.6, 1.0))
)

result = outer.cut(inner)

# Add tabs
for edge, pos, offset in tabs:
    px, py = edge_point(edge, pos, outer_w, outer_h)
    nx, ny = outward_normal(edge)
    cx = px + nx * offset
    cy = py + ny * offset

    tab = (
        cq.Workplane("XY")
        .center(cx, cy)
        .circle(tab_radius)
        .extrude(plate_thickness)
    )
    result = result.union(tab)

# Drill tab holes
for edge, pos, offset in tabs:
    px, py = edge_point(edge, pos, outer_w, outer_h)
    nx, ny = outward_normal(edge)
    cx = px + nx * offset
    cy = py + ny * offset

    hole = (
        cq.Workplane("XY")
        .center(cx, cy)
        .circle(hole_diameter / 2)
        .extrude(plate_thickness + 2.0)
        .translate((0, 0, -1.0))
    )
    result = result.cut(hole)

# Light edge softening
result = result.edges("|Z").fillet(0.6)
